import fs from "node:fs";
import os from "node:os";
import path from "node:path";
/**
 * Read `~/.claude/plugins/installed_plugins.json` and return the distinct
 * scopes the given `<plugin>@<marketplace>` key is installed at. Returns an
 * empty array when the file is missing, malformed, or the key is absent —
 * callers should treat that as "scope detection isn't available".
 *
 * `homeDir` overrides `os.homedir()` (for tests).
 */
export function detectClaudeInstallScopes(pluginKey, homeDir = os.homedir()) {
    try {
        const installedPath = path.join(homeDir, ".claude", "plugins", "installed_plugins.json");
        const content = fs.readFileSync(installedPath, "utf-8");
        const data = JSON.parse(content);
        const entries = data.plugins?.[pluginKey] ?? [];
        const scopes = new Set();
        for (const entry of entries) {
            if (entry.scope) {
                scopes.add(entry.scope);
            }
        }
        return Array.from(scopes);
    }
    catch {
        return [];
    }
}
